package org.apache.commons.csv;
import java.io.BufferedReader;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader readerSpy;

    @BeforeEach
    void setUp() throws IOException {
        Reader mockReader = mock(Reader.class);
        readerSpy = spy(new ExtendedBufferedReader(mockReader));
    }

    @Test
    void testReadLine_nonNullNonEmptyLine() throws Exception {
        // Arrange
        String testLine = "Hello, World!";
        doReturn(testLine).when(readerSpy).readLine_super();

        // Act
        String result = readerSpy.readLine();

        // Assert
        assertEquals(testLine, result);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastCharValue = lastCharField.getInt(readerSpy);
        assertEquals(testLine.charAt(testLine.length() - 1), lastCharValue);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounterValue = lineCounterField.getInt(readerSpy);
        assertEquals(1, lineCounterValue);
    }

    @Test
    void testReadLine_nonNullEmptyLine() throws Exception {
        // Arrange
        String testLine = "";
        doReturn(testLine).when(readerSpy).readLine_super();

        // Act
        String result = readerSpy.readLine();

        // Assert
        assertEquals(testLine, result);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastCharValue = lastCharField.getInt(readerSpy);
        assertEquals(ExtendedBufferedReader.UNDEFINED, lastCharValue);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounterValue = lineCounterField.getInt(readerSpy);
        assertEquals(1, lineCounterValue);
    }

    @Test
    void testReadLine_nullLine() throws Exception {
        // Arrange
        doReturn(null).when(readerSpy).readLine_super();

        // Act
        String result = readerSpy.readLine();

        // Assert
        assertNull(result);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastCharValue = lastCharField.getInt(readerSpy);
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastCharValue);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounterValue = lineCounterField.getInt(readerSpy);
        assertEquals(0, lineCounterValue);
    }

    // Helper method to mock super.readLine() since readLine is overridden
    // We'll use reflection to replace super.readLine() call in readLine() with this method call for mocking
    // But since super.readLine() cannot be mocked directly, we create a spy and override readLine_super() method.

    // To do this, we add a package-private method readLine_super() in ExtendedBufferedReader to call super.readLine()
    // And then in tests we mock readLine_super() instead.

}
